code = """import json

# Get order items for the product
orderitems = locals()['var_functions.query_db:22']
orderitem_ids = set()
for item in orderitems:
    orderitem_id = item['Id']
    orderitem_ids.add(orderitem_id)
    # Add both with and without #
    if orderitem_id.startswith('#'):
        orderitem_ids.add(orderitem_id[1:])
    else:
        orderitem_ids.add('#' + orderitem_id)

# Get all cases from past 5 months
cases = locals()['var_functions.query_db:14']

# Find matching cases
matching_cases = []
for case in cases:
    case_orderitem = case.get('orderitemid__c')
    if case_orderitem and case_orderitem in orderitem_ids:
        matching_cases.append(case)

# Count issues
issue_counts = {}
for case in matching_cases:
    issue_id = case.get('issueid__c')
    if issue_id:
        issue_counts[issue_id] = issue_counts.get(issue_id, 0) + 1

# Find most frequent
most_frequent_issue = None
max_count = 0
for issue_id, count in issue_counts.items():
    if count > max_count:
        max_count = count
        most_frequent_issue = issue_id

print('__RESULT__:')
print(json.dumps({
    'matching_cases_count': len(matching_cases),
    'issue_counts': issue_counts,
    'most_frequent_issue': most_frequent_issue,
    'matching_cases': matching_cases
}))"""

